import{_ as a,c as i,o as s,aN as r}from"./chunks/framework.BRm39z_l.js";const h=JSON.parse('{"title":"Redis基础","description":"","frontmatter":{},"headers":[],"relativePath":"redis/01.Redis基础.md","filePath":"redis/01.Redis基础.md"}'),d={name:"redis/01.Redis基础.md"};function t(o,e,n,l,p,_){return s(),i("div",null,e[0]||(e[0]=[r('<h1 id="redis基础" tabindex="-1">Redis基础 <a class="header-anchor" href="#redis基础" aria-label="Permalink to &quot;Redis基础&quot;">​</a></h1><nav class="table-of-contents"><ul><li><a href="#redis-有哪些数据类型">Redis 有哪些数据类型？</a></li><li><a href="#redis-为什么快呢">Redis 为什么快呢？</a></li></ul></nav><h2 id="redis-有哪些数据类型" tabindex="-1">Redis 有哪些数据类型？ <a class="header-anchor" href="#redis-有哪些数据类型" aria-label="Permalink to &quot;Redis 有哪些数据类型？&quot;">​</a></h2><p>Redis ⽀持五种基本数据类型，分别是字符串、列表、哈希、集合和有序集合</p><p>还有三种扩展数据类型，分别是⽤于位级操作的 Bitmap、⽤于基数估算的 HyperLogLog、⽀持存储和查询地理坐标的 GEO</p><h2 id="redis-为什么快呢" tabindex="-1">Redis 为什么快呢？ <a class="header-anchor" href="#redis-为什么快呢" aria-label="Permalink to &quot;Redis 为什么快呢？&quot;">​</a></h2><p>因为他是存储在内存中的，内存的存储速度本身就比硬盘多了几个量级</p><p>其次，redis 采用了多路复用技术来处理客户端请求和 redis 命令</p><p>简单来说多路复用就是在只有一个线程的情况下，同时鉴定成千上万个客户端的连接，解决传统 io 模型中每个连接需要一个独立线程带来的开销</p><p>还有一点就是 redis 对底层的数据结构进行了优化</p><p>⽐如说 String 的底层数据结构动态字符串⽀持动态扩容、预分配冗余空间，能够减少内存碎⽚和内存分配的开销</p>',11)]))}const R=a(d,[["render",t]]);export{h as __pageData,R as default};
